// Determine if we should create a new application record.
// Rules:
// - If job has status = submitted → skip (never reapply)
// - If job has status = rejected_by_user → skip
// - If job has status = pending_approval or draft_ready → skip (already in flight)
// - If application record exists with submitted_at set → skip
// - Otherwise → proceed to draft

const job = $('Check Existing Job').first().json;
const app = $('Check Existing Application').first().json;
const incoming = $('Webhook: Receive Eligible Job').first().json;

const blockedStatuses = ['submitted', 'rejected_by_user', 'pending_approval', 'draft_ready'];

if (blockedStatuses.includes(job?.status)) {
  return [{ json: { action: 'skip', reason: `job_status=${job.status}`, job_key: incoming.job_key } }];
}

if (app?.submitted_at) {
  return [{ json: { action: 'skip', reason: 'already_submitted', job_key: incoming.job_key } }];
}

if (app?.draft_status && ['draft_complete', 'needs_user_input', 'in_progress'].includes(app.draft_status)) {
  return [{ json: { action: 'skip', reason: `draft_in_flight: ${app.draft_status}`, job_key: incoming.job_key } }];
}

// New, non-duplicate job — load all profiles and create one application per profile
const fs = require('fs');
const profilePaths = (process.env.APPLICANT_PROFILE_PATHS || '').split(',').map(p => p.trim()).filter(Boolean);
const profiles = profilePaths.map(p => JSON.parse(fs.readFileSync(p, 'utf8')));

if (profiles.length === 0) {
  return [{ json: { action: 'error', reason: 'no_profiles_configured', job_key: incoming.job_key } }];
}

return profiles.map(profile => ({
  json: { action: 'create', job_key: incoming.job_key, job: incoming, profile_id: profile.profile_id }
}));
